// Config central de Eight Academy — 4 sedes x 4 query types
const SEDES = [
  { id: 'kids', name: 'Eight Kids', address: 'Los Alhelíes E15-44, Quito', lat: -0.2180, lng: -78.4890, nivel: 'Inicial', nse_base: 'B+' },
  { id: 'primaria', name: 'Eight Academy Primaria', address: 'Av. 6 de Diciembre y Manuel Zambrano, Quito', lat: -0.1950, lng: -78.4860, nivel: 'Primaria', nse_base: 'A' },
  { id: 'secundaria', name: 'Eight Academy Secundaria', address: 'Av. La Prensa y Nicolás López, Quito', lat: -0.1267, lng: -78.5003, nivel: 'Secundaria', nse_base: 'B+' },
  { id: 'zoobotanica', name: 'Zoo Botánica Academy', address: 'Guayllabamba, Ecuador', lat: -0.0639, lng: -78.3618, nivel: 'Todos', nse_base: 'B' }
];

// Tipos de prospecto a buscar (proxies de familias con hijos y poder adquisitivo)
const QUERY_TYPES = [
  { type: 'family_health', query: 'pediatría clínica infantil', reason: 'Familias con hijos, investigan salud = invierten en educación' },
  { type: 'education_investment', query: 'academia refuerzo académico inglés niños', reason: 'Padres que invierten en educación adicional = perfil Eight Academy' },
  { type: 'premium_residential', query: 'urbanización conjunto residencial privado', reason: 'Hogares en zonas cerradas = NSE B+ mínimo' },
  { type: 'premium_lifestyle', query: 'gym premium club deportivo familiar', reason: 'Estilo de vida premium = pueden pagar $350/mes' }
];

// Generar combinaciones sede x query
const jobs = [];
for (const sede of SEDES) {
  for (const qtype of QUERY_TYPES) {
    jobs.push({
      sede_id: sede.id,
      sede_name: sede.name,
      sede_address: sede.address,
      sede_lat: sede.lat,
      sede_lng: sede.lng,
      sede_nivel: sede.nivel,
      sede_nse_base: sede.nse_base,
      query: qtype.query,
      query_type: qtype.type,
      query_reason: qtype.reason,
      location: `${sede.lat},${sede.lng}`,
      radius: 10000
    });
  }
}

console.log(`Generados ${jobs.length} jobs de búsqueda (${SEDES.length} sedes x ${QUERY_TYPES.length} query types)`);
return jobs.map(j => ({ json: j }));

// Parsear resultados de Nominatim + enriquecer con contexto
const places = $input.first().json;  // Nominatim returns array directly
const jobData = $('🔄 Loop 16 Jobs').first().json;

if (!places || !Array.isArray(places) || places.length === 0) {
  console.log('No places found for query:', jobData.query);
  return [];
}

const enriched = places.slice(0, 5).map(place => {
  const address = place.display_name || '';
  const lat = parseFloat(place.lat) || jobData.sede.lat;
  const lng = parseFloat(place.lon) || jobData.sede.lng;

  // Calculate distance from sede
  const dLat = lat - jobData.sede.lat;
  const dLng = lng - jobData.sede.lng;
  const distKm = Math.sqrt(dLat*dLat + dLng*dLng) * 111;

  return {
    json: {
      place_id: place.place_id || Math.random().toString(36),
      lead_name: place.name || address.split(',')[0],
      lead_address: address,
      lead_lat: lat,
      lead_lng: lng,
      lead_type: jobData.queryType,
      lead_sede: jobData.sede.name,
      lead_distancia: Math.round(distKm * 10) / 10,
      lead_hook: jobData.queryType + ' cerca de ' + jobData.sede.name,
      lead_perfil: 'Prospecto ' + jobData.sede.nivel + ' | ' + jobData.queryType,
      rating: place.importance ? Math.round(place.importance * 5) : 3,
      user_ratings_total: 10,
      search_query: jobData.query,
      sede_id: jobData.sede.id,
      nse_zona: jobData.sede.nse || 'B+'
    }
  };
});

return enriched;

