// Combinar datos del lugar + análisis IA
const aiResp = $input.first().json;
const rawText = aiResp.content?.[0]?.text || '{}';
const placeData = $('🔄 Loop Cada Lugar').first().json;

let ai = {};
try {
  const cleaned = rawText.replace(/```json/gi, '').replace(/```/gi, '').trim();
  ai = JSON.parse(cleaned);
} catch(e) {
  ai = { poder_adquisitivo_score: 5, intent_score: 5, zona_nse: 'B', tech_affinity: 5, fit_score: 5, score_final: 5, tier: 'B', perfil_familiar: 'Familia media Quito', hook_personalizado: 'Sin matrícula 2026/2027', canal_contacto: 'whatsapp', mensaje_promo: 'Conoce más sin compromiso', urgencia: 'media', accion_recomendada: 'Contactar por WhatsApp' };
}

return [{
  json: {
    // CRM Fields
    Nombre_Lugar: placeData.name,
    Tipo_Prospecto: placeData.query_type,
    Direccion: placeData.address,
    Sede_Mas_Cercana: placeData.sede_mas_cercana,
    Nivel_Sede: placeData.sede_nivel,
    Distancia_Sede_km: placeData.distancia_sede_km,
    Rating_Google: placeData.rating,
    Total_Resenas: placeData.total_ratings,
    Lat: placeData.lat,
    Lng: placeData.lng,
    // AI Scoring
    Score_Poder_Adquisitivo: ai.poder_adquisitivo_score || 0,
    Score_Intencion: ai.intent_score || 0,
    Score_Tech_Affinity: ai.tech_affinity || 0,
    Score_Fit_EightAcademy: ai.fit_score || 0,
    Score_Final: ai.score_final || 0,
    Zona_NSE: ai.zona_nse || 'B',
    Tier: ai.tier || 'C',
    Perfil_Familiar: ai.perfil_familiar || '',
    Hook_Personalizado: ai.hook_personalizado || '',
    Canal_Contacto: ai.canal_contacto || 'whatsapp',
    Mensaje_Promo: ai.mensaje_promo || '',
    Urgencia: ai.urgencia || 'media',
    Accion_Recomendada: ai.accion_recomendada || '',
    // Metadata
    Estado: 'Nuevo',
    Fuente: 'Geo Family Discovery v2',
    Fecha_Descubierto: placeData.discovered_at,
    Place_ID: placeData.place_id
  }
}];

